-- Atualiza as diretrizes do modulo instagram-text-post para incluir:
-- - Campo swipeText no JSON de saida
-- - Instrucoes especificas para Tipo 1 (text post) e Tipo 2 (image cover)
-- Conteudo em base64 para evitar mojibake no Windows (supabase db push).

UPDATE modules
SET content = convert_from(decode(
  '',
  'base64'), 'UTF8')
WHERE slug = 'instagram-text-post-guidelines';
